('ONET-SCHOOL_BUS_MONITORS', 'source_onet_school_bus_monitors', 'School Bus Monitors', 'School Bus Monitors is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Maintain order among students on a school bus. Duties include helping students safely board and exit and communicating behavioral problems. May perform pretrip and posttrip inspections and prepare for and assist in emergency evacuations.', ARRAY['Bus Monitor','School Bus Aide','School Bus Assistant','School Bus Attendant','School Bus Escort','School Bus Matron','School Bus Monitor']::text[], ARRAY['School Bus Monitors','Bus Monitor','School Bus Aide','School Bus Assistant','School Bus Attendant','School Bus Escort','School Bus Matron','School Bus Monitor']::text[], ARRAY['Operating system software','Internet browser software']::text[], '{"source_imported_skills":["Operating system software","Internet browser software"]}'::jsonb, '["approved_capability","industry_context","employment_model"]'::jsonb, '["source_imported_role","skills","tasks"]'::jsonb, '["approved_capability_without_mapping"]'::jsonb, 'source_imported_role', '{"Canada":"Needs mapping to NOC/OaSIS before Canada production routing.","India":"Needs mapping to NCO/NSDC/NOS before India production routing.","USA":"O*NET-origin terms can map directly to USA context; ESCO-origin terms need USA mapping."}'::jsonb, '4', 'observed', 'draft'),
